292	// legacySkillSymlinkDirs returns the relative names of skill directories
293	// (e.g. ".agents/skills", ".claude/skills") under workingDir that contain
294	// at least one symlink. A symlink indicates a pre-FEAT-015 install.
295	func legacySkillSymlinkDirs(workingDir string) []string {
296		if workingDir == "" {
297			return nil
298		}
299		var found []string
300		for _, rel := range []string{".agents/skills", ".claude/skills"} {
301			dir := filepath.Join(workingDir, rel)
302			entries, err := os.ReadDir(dir)
303			if err != nil {
304				continue
305			}
306			for _, e := range entries {
307				info, err := e.Info()
308				if err != nil {
309					continue
310				}
311				if info.Mode()&os.ModeSymlink != 0 {
312					found = append(found, rel)
313					break
314				}
315			}
316		}
317		return found
318	}
