320	// checkBinaryInstallLocation verifies the running binary is at the canonical install
321	// location ($HOME/.local/bin/ddx) and scans PATH for other ddx copies whose
322	// SHA-256 differs from the running binary.
323	func checkBinaryInstallLocation(executable string) []DiagnosticIssue {
324		var issues []DiagnosticIssue
325	
326		homeDir, err := os.UserHomeDir()
327		if err != nil {
328			return issues
329		}
330	
331		canonicalPath := filepath.Join(homeDir, ".local", "bin", "ddx")
332	
333		// (2) Check whether running binary matches the canonical install location.
334		resolvedExec, _ := filepath.EvalSymlinks(executable)
335		if resolvedExec == "" {
336			resolvedExec = executable
337		}
338		resolvedCanonical, _ := filepath.EvalSymlinks(canonicalPath)
339		execMatchesCanonical := resolvedExec == canonicalPath ||
340			(resolvedCanonical != "" && resolvedExec == resolvedCanonical)
341		if !execMatchesCanonical {
342			issues = append(issues, DiagnosticIssue{
343				Type:        "binary_not_canonical",
344				Description: fmt.Sprintf("Running binary (%s) is not at canonical install location (%s)", executable, canonicalPath),
345				Remediation: []string{
346					"Re-run install.sh to reinstall to the canonical location",
347					fmt.Sprintf("Or ensure %s is earlier in your PATH", filepath.Dir(canonicalPath)),
348				},
349			})
350		}
351	
352		// (3) Walk PATH and flag any ddx copy whose SHA-256 differs from the running binary.
353		runningSHA, err := computeFileSHA256(executable)
354		if err != nil {
355			return issues
356		}
357	
358		seen := make(map[string]bool)
359		for _, dir := range filepath.SplitList(os.Getenv("PATH")) {
360			candidate := filepath.Join(dir, "ddx")
361			if seen[candidate] {
362				continue
363			}
364			seen[candidate] = true
365	
366			info, err := os.Stat(candidate)
367			if err != nil || !info.Mode().IsRegular() || info.Mode()&0111 == 0 {
368				continue
369			}
370	
371			candidateSHA, err := computeFileSHA256(candidate)
372			if err != nil {
373				continue
374			}
375	
376			if candidateSHA == runningSHA {
377				continue // same binary, not stale
378			}
379	
380			issues = append(issues, DiagnosticIssue{
381				Type:        "binary_sha_mismatch",
382				Description: fmt.Sprintf("Stale ddx copy on PATH: %s (SHA-256 differs from running binary)", candidate),
383				Remediation: []string{
384					fmt.Sprintf("rm %s && cp %s %s", candidate, executable, candidate),
385					"Or re-run install.sh to update all copies",
386				},
387			})
388		}
389	
390		return issues
391	}
