393	// computeFileSHA256 returns the hex-encoded SHA-256 digest of the named file.
394	func computeFileSHA256(path string) (string, error) {
395		f, err := os.Open(path)
396		if err != nil {
397			return "", err
398		}
399		defer f.Close()
400	
401		h := sha256.New()
402		if _, err := io.Copy(h, f); err != nil {
403			return "", err
404		}
405		return hex.EncodeToString(h.Sum(nil)), nil
406	}
