446	// checkLibraryPath verifies library path is accessible
447	func checkLibraryPathFromWorkingDir(workingDir string) bool {
448		cfg, err := config.LoadWithWorkingDir(workingDir)
449		if err != nil {
450			return false
451		}
452	
453		if cfg.Library == nil || cfg.Library.Path == "" {
454			return false
455		}
456	
457		// Resolve library path relative to working directory
458		libPath := cfg.Library.Path
459		if !filepath.IsAbs(libPath) {
460			libPath = filepath.Join(workingDir, libPath)
461		}
462	
463		_, err = os.Stat(libPath)
464		return err == nil
465	}
