524				}
525				fmt.Println()
526			}
527		}
528	
529		if verbose {
530			fmt.Println("💡 Additional Troubleshooting Tips:")
531			fmt.Println("  • Run 'ddx doctor' periodically to check system health")
532			fmt.Println("  • Use 'ddx doctor --verbose' for detailed diagnostics")
533			fmt.Println("  • Check DDX documentation at https://github.com/DocumentDrivenDX/ddx")
534			fmt.Println("  • Report issues at https://github.com/DocumentDrivenDX/ddx/issues")
