574	// checkInstalledLaunchers checks whether installed packages with Scripts mappings
575	// have a working launcher in the target path (e.g. ~/.local/bin/helix).
576	func checkInstalledLaunchers(verbose bool) {
577		state, err := registry.LoadState()
578		if err != nil || len(state.Installed) == 0 {
579			return
580		}
581	
582		reg := registry.BuiltinRegistry()
583		for _, entry := range state.Installed {
584			pkg, err := reg.Find(entry.Name)
585			if err != nil || pkg.Install.Scripts == nil {
586				continue
587			}
588	
589			dst := registry.ExpandHome(pkg.Install.Scripts.Target)
590			name := filepath.Base(dst)
591			fmt.Printf("✓ Checking %s launcher... ", name)
592	
593			li, err := os.Lstat(dst)
594			if os.IsNotExist(err) {
595				fmt.Printf("❌ MISSING (%s not found, run: ddx install %s)\n", dst, pkg.Name)
596				continue
597			}
598			if err != nil {
599				fmt.Printf("❌ error: %v\n", err)
600				continue
601			}
602	
603			if li.Mode()&os.ModeSymlink != 0 {
604				target, _ := os.Readlink(dst)
605				if verbose {
606					fmt.Printf("✅ OK (developer symlink → %s)\n", target)
607				} else {
608					fmt.Println("✅ OK (developer symlink)")
609				}
610				continue
611			}
612	
613			// Regular file — check it's executable.
614			if li.Mode()&0111 != 0 {
615				fmt.Printf("✅ OK (%s)\n", dst)
616			} else {
617				fmt.Printf("⚠️  not executable (run: chmod +x %s)\n", dst)
618			}
619		}
620	}
