622	// checkInstalledPlugins audits installed plugin roots and manifests.
623	func checkInstalledPlugins(verbose bool) []DiagnosticIssue {
624		state, err := registry.LoadState()
625		if err != nil || len(state.Installed) == 0 {
626			return nil
627		}
628	
629		reg := registry.BuiltinRegistry()
630		var issues []DiagnosticIssue
631	
632		for _, entry := range state.Installed {
633			fallback, _ := reg.Find(entry.Name)
634			entryType := entry.Type
635			if entryType == "" && fallback != nil {
636				entryType = fallback.Type
637			}
638			if entryType == "" && !looksLikePluginInstall(entry) {
639				continue
640			}
641			switch entryType {
642			case registry.PackageTypePlugin, registry.PackageTypeWorkflow:
643			case "":
644			default:
645				continue
646			}
647			for _, issue := range registry.AuditInstalledEntry(entry, fallback) {
648				diag := DiagnosticIssue{
649					Type:        "plugin_validation",
650					Description: issue.Error(),
651					Remediation: []string{
652						"Check package.yaml, skill directories, and installed symlinks for the path shown above",
653						"Reinstall the package after fixing the source tree or manifest",
654					},
655					SystemInfo: map[string]string{
656						"plugin": entry.Name,
657					},
658				}
659				if verbose {
660					diag.SystemInfo["source"] = entry.Source
661				}
662				issues = append(issues, diag)
