702	// checkGitRepoHealth detects git-repo corruption from prior ddx incidents:
703	//  1. core.bare=true on a repo that has a working tree (not actually bare)
704	//  2. Stray core.worktree that does not match the actual toplevel
705	//  3. extensions.worktreeConfig not enabled (warning only)
706	//
707	// If fix is true, conditions (1) and (2) are remediated with `git config --unset`.
708	// (3) is always a warning — never auto-fixed, since enabling per-worktree config
709	// is a user-facing choice.
710	func checkGitRepoHealth(workingDir string, fix bool) []DiagnosticIssue {
711		var issues []DiagnosticIssue
712		ctx := context.Background()
713	
714		// Bail out quietly if this directory isn't a git repo at all. We can't rely
715		// on `--is-inside-work-tree` here because the corruption we're looking for
716		// (core.bare=true on a repo that has a working tree) causes git to report
717		// "false" for that query. Instead, probe `--git-dir`, which succeeds on both
718		// bare and non-bare repos.
719		gitDirProbe := gitpkg.Command(ctx, workingDir, "rev-parse", "--git-dir")
720		gdOut, err := gitDirProbe.Output()
721		if err != nil {
722			return nil
723		}
724		gitDirRaw := strings.TrimSpace(string(gdOut))
725		if gitDirRaw == "" {
726			return nil
727		}
728	
729		// A "real" working tree on disk: either .git is a directory/file at
730		// workingDir, or git reports a separate work-tree via --show-toplevel.
731		// If neither holds, this is a genuinely bare repo → skip the checks.
732		hasWorkTreeOnDisk := false
733		if _, statErr := os.Stat(filepath.Join(workingDir, ".git")); statErr == nil {
734			hasWorkTreeOnDisk = true
735		}
736		if !hasWorkTreeOnDisk {
737			// Maybe we're inside a linked worktree where git treats us normally.
738			inWT := gitpkg.Command(ctx, workingDir, "rev-parse", "--is-inside-work-tree")
739			if b, err := inWT.Output(); err == nil && strings.TrimSpace(string(b)) == "true" {
740				hasWorkTreeOnDisk = true
741			}
742		}
743		if !hasWorkTreeOnDisk {
744			return nil
745		}
746	
747		gitConfigValue := func(key string) (string, bool) {
748			c := gitpkg.Command(ctx, workingDir, "config", "--local", "--get", key)
749			b, err := c.Output()
750			if err != nil {
751				return "", false
752			}
753			return strings.TrimSpace(string(b)), true
754		}
755		gitConfigUnset := func(key string) error {
756			c := gitpkg.Command(ctx, workingDir, "config", "--local", "--unset", key)
757			return c.Run()
758		}
759	
760		// (1) core.bare=true on a repo with a working tree → corruption.
761		if val, ok := gitConfigValue("core.bare"); ok && val == "true" {
762			desc := "core.bare=true is set on a repository that has a working tree (not actually bare)"
763			rem := []string{"git config --unset core.bare"}
764			if fix {
765				if err := gitConfigUnset("core.bare"); err == nil {
766					desc += " — removed"
767				} else {
768					desc += fmt.Sprintf(" — unset failed: %v", err)
769				}
770			}
771			issues = append(issues, DiagnosticIssue{
772				Type:        "git_core_bare_corruption",
773				Description: desc,
774				Remediation: rem,
775			})
776		}
777	
778		// (2) Stray core.worktree that doesn't match the directory we're running
779		// against. Compare to workingDir directly — asking git for --show-toplevel
780		// would just echo back core.worktree.
781		if worktreeVal, ok := gitConfigValue("core.worktree"); ok && worktreeVal != "" {
782			actual := workingDir
783	
784			cmpVal := worktreeVal
785			if !filepath.IsAbs(cmpVal) {
786				cmpVal = filepath.Clean(filepath.Join(gitDirRaw, worktreeVal))
787			}
788			resolvedCmp, _ := filepath.EvalSymlinks(cmpVal)
789			if resolvedCmp == "" {
790				resolvedCmp = cmpVal
791			}
792			resolvedActual, _ := filepath.EvalSymlinks(actual)
793			if resolvedActual == "" {
794				resolvedActual = actual
795			}
796	
797			if actual != "" && resolvedCmp != resolvedActual {
798				desc := fmt.Sprintf("core.worktree=%q does not match actual worktree %q", worktreeVal, actual)
799				rem := []string{"git config --unset core.worktree"}
800				if fix {
801					if err := gitConfigUnset("core.worktree"); err == nil {
802						desc += " — removed"
803					} else {
804						desc += fmt.Sprintf(" — unset failed: %v", err)
805					}
806				}
807				issues = append(issues, DiagnosticIssue{
808					Type:        "git_stray_core_worktree",
809					Description: desc,
810					Remediation: rem,
811				})
812			}
813		}
814	
815		// (3) extensions.worktreeConfig not enabled → warning only.
816		val, ok := gitConfigValue("extensions.worktreeConfig")
817		if !ok || val != "true" {
818			issues = append(issues, DiagnosticIssue{
819				Type:        "git_worktree_config_disabled",
820				Description: "extensions.worktreeConfig is not enabled; per-worktree config changes can corrupt the shared .git/config",
821				Remediation: []string{
822					"git config extensions.worktreeConfig true",
823				},
824			})
825		}
826	
827		return issues
828	}
