831	type packageJSONCheck struct {
832		Dir      string // relative path from project root (e.g. "website")
833		HasPkg   bool   // package.json exists
834		NeedsBun bool   // node_modules missing or stale vs bun.lock
835		Reason   string // "missing" | "stale"
836	}
