838	// knownPackageJSONDirs are the subdirectories (relative to workingDir) that
839	// may contain a package.json. "" means the repo root itself.
840	var knownPackageJSONDirs = []string{"", "website", "cli/internal/server/frontend"}
841	
842	// checkPackageJSONLocations scans the known package.json locations under
843	// workingDir and returns a DiagnosticIssue for each location where
844	// node_modules/ is absent or older than bun.lock.
845	func checkPackageJSONLocations(workingDir string) []DiagnosticIssue {
846		var issues []DiagnosticIssue
847	
848		for _, rel := range knownPackageJSONDirs {
849			var dir string
850			if rel == "" {
851				dir = workingDir
852			} else {
853				dir = filepath.Join(workingDir, filepath.FromSlash(rel))
854			}
855	
856			pkgPath := filepath.Join(dir, "package.json")
857			if _, err := os.Stat(pkgPath); err != nil {
858				continue // no package.json here
859			}
860	
861			label := rel
862			if label == "" {
863				label = "(repo root)"
864			}
865	
866			nmPath := filepath.Join(dir, "node_modules")
867			nmInfo, nmErr := os.Stat(nmPath)
868			if nmErr != nil {
869				// node_modules missing entirely
870				issues = append(issues, DiagnosticIssue{
871					Type:        "node_modules_missing",
872					Description: fmt.Sprintf("node_modules/ missing in %s", label),
873					Remediation: []string{
874						fmt.Sprintf("cd %s && bun install", dir),
875					},
876					SystemInfo: map[string]string{"package_json": pkgPath},
877				})
878				continue
879			}
880	
881			// Check if bun.lock is newer than node_modules
882			lockPath := filepath.Join(dir, "bun.lock")
883			lockInfo, lockErr := os.Stat(lockPath)
884			if lockErr == nil && lockInfo.ModTime().After(nmInfo.ModTime()) {
885				issues = append(issues, DiagnosticIssue{
886					Type:        "node_modules_stale",
887					Description: fmt.Sprintf("node_modules/ in %s is older than bun.lock (run bun install)", label),
888					Remediation: []string{
889						fmt.Sprintf("cd %s && bun install", dir),
890					},
891					SystemInfo: map[string]string{"package_json": pkgPath},
892				})
893			}
894		}
895	
896		return issues
897	}
