191	func GetCurrentBranch() (string, error) {
192		// Check if we're in a git repository
193		if !IsRepository(".") {
194			return "", fmt.Errorf("not a git repository")
195		}
196	
197		ctx, cancel := context.WithTimeout(context.Background(), 5*time.Second)
198		defer cancel()
