225	// CommitChanges commits changes with a message
226	func CommitChanges(message string) error {
227		// Check if we're in a git repository
228		if !IsRepository(".") {
229			return fmt.Errorf("not a git repository")
230		}
231	
232		// Validate and sanitize commit message
233		if err := validateCommitMessage(message); err != nil {
234			return fmt.Errorf("invalid commit message: %w", err)
235		}
236	
237		sanitizedMessage := sanitizeCommitMessage(message)
238	
239		ctx, cancel := context.WithTimeout(context.Background(), 30*time.Second)
240		defer cancel()
241	
242		// Add all changes
243		cmd := Command(ctx, "", "add", "-A")
244		if err := cmd.Run(); err != nil {
245			return fmt.Errorf("failed to add changes")
246		}
247	
248		// Check if there are any changes to commit
249		hasChanges, err := HasUncommittedChanges(".")
250		if err != nil {
251			return fmt.Errorf("failed to check for changes: %w", err)
252		}
253		if !hasChanges {
254			return fmt.Errorf("no changes to commit")
255		}
256	
257		// Commit with sanitized message
258		cmd = Command(ctx, "", "commit", "-m", sanitizedMessage)
259		_, err = cmd.CombinedOutput()
260		if err != nil {
261			return fmt.Errorf("failed to commit changes")
262		}
263	
264		return nil
265	}
