278	// isValidPath validates a file system path
279	func isValidPath(path string) bool {
280		if path == "" {
281			return false
282		}
283	
284		// Check cache first for performance
285		if cached, exists := pathValidationCache.Load(path); exists {
286			return cached.(bool)
287		}
288	
289		// Basic path validation
290		cleanPath := filepath.Clean(path)
291	
292		// Prevent path traversal
293		if strings.Contains(cleanPath, "..") {
294			pathValidationCache.Store(path, false)
295			return false
296		}
297	
298		// Prevent absolute paths outside current working directory for safety
299		if filepath.IsAbs(cleanPath) {
300			pwd, err := filepath.Abs(".")
301			if err != nil {
302				pathValidationCache.Store(path, false)
303				return false
304			}
305	
306			// Check if the path is within or equal to current directory
307			rel, err := filepath.Rel(pwd, cleanPath)
308			if err != nil || strings.HasPrefix(rel, "..") {
309				pathValidationCache.Store(path, false)
310				return false
311			}
312		}
313	
314		pathValidationCache.Store(path, true)
315		return true
316	}
