318	// validatePrefix validates a git subtree prefix
319	func validatePrefix(prefix string) error {
320		if prefix == "" {
321			return fmt.Errorf("prefix cannot be empty")
322		}
323	
324		if len(prefix) > 255 {
325			return fmt.Errorf("prefix too long (max 255 characters)")
326		}
327	
328		if !validPrefix.MatchString(prefix) {
329			return fmt.Errorf("prefix contains invalid characters (only alphanumeric, dots, underscores, hyphens, and forward slashes allowed)")
330		}
331	
332		// Prevent path traversal in prefix
333		if strings.Contains(prefix, "..") {
334			return fmt.Errorf("prefix cannot contain path traversal sequences")
335		}
336	
337		// Prevent absolute paths
338		if filepath.IsAbs(prefix) {
339			return fmt.Errorf("prefix cannot be an absolute path")
340		}
341	
342		return nil
343	}
