345	// validateRepoURL validates a git repository URL
346	func validateRepoURL(repoURL string) error {
347		if repoURL == "" {
348			return fmt.Errorf("repository URL cannot be empty")
349		}
350	
351		if len(repoURL) > 2048 {
352			return fmt.Errorf("repository URL too long (max 2048 characters)")
353		}
354	
355		// Parse URL to validate format
356		u, err := url.Parse(repoURL)
357		if err != nil {
358			return fmt.Errorf("invalid URL format: %w", err)
359		}
360	
361		// Only allow specific schemes for security
362		allowedSchemes := map[string]bool{
363			"http":  true,
364			"https": true,
365			"git":   true,
366			"ssh":   true,
367		}
