160	// HasUncommittedChanges checks if there are uncommitted changes in a directory
161	func HasUncommittedChanges(path string) (bool, error) {
162		// Set default path and validate
163		if path == "" {
164			path = "."
165		}
166	
167		if !isValidPath(path) {
168			return false, fmt.Errorf("invalid path: %s", path)
169		}
170	
171		// Clean the path to prevent path traversal
172		cleanPath := filepath.Clean(path)
173	
174		if !IsRepository(cleanPath) {
175			return false, fmt.Errorf("not a git repository: %s", cleanPath)
176		}
177	
178		ctx, cancel := context.WithTimeout(context.Background(), 10*time.Second)
179		defer cancel()
180	
181		cmd := Command(ctx, cleanPath, "status", "--porcelain")
182		output, err := cmd.Output()
183		if err != nil {
184			return false, fmt.Errorf("failed to check git status")
185		}
186	
187		return len(strings.TrimSpace(string(output))) > 0, nil
188	}
