190	// GetCurrentBranch returns the current git branch
191	func GetCurrentBranch() (string, error) {
192		// Check if we're in a git repository
193		if !IsRepository(".") {
194			return "", fmt.Errorf("not a git repository")
195		}
196	
197		ctx, cancel := context.WithTimeout(context.Background(), 5*time.Second)
198		defer cancel()
199	
200		cmd := Command(ctx, "", "branch", "--show-current")
201		output, err := cmd.Output()
202		if err != nil {
203			return "", fmt.Errorf("failed to get current branch")
204		}
205	
206		branch := strings.TrimSpace(string(output))
207		if branch == "" {
208			// Fallback for older git versions or detached HEAD
209			cmd = Command(ctx, "", "rev-parse", "--abbrev-ref", "HEAD")
210			output, err = cmd.Output()
211			if err != nil {
212				return "", fmt.Errorf("failed to get branch name")
213			}
214			branch = strings.TrimSpace(string(output))
215		}
216	
217		// Validate branch name before returning
218		if err := validateBranchName(branch); err != nil {
219			return "", fmt.Errorf("invalid branch name detected: %w", err)
220		}
221	
222		return branch, nil
223	}
