56	func checkpointNameValid(name string) error {
57		if name == "" {
58			return fmt.Errorf("checkpoint name cannot be empty")
59		}
60		if !validCheckpointName.MatchString(name) {
61			return fmt.Errorf("checkpoint name %q contains invalid characters (only alphanumeric, hyphens, and dots allowed)", name)
62		}
63		return nil
64	}
65	
66	func runCheckpointCreate(cmd *cobra.Command, prefix, name string) error {
67		if err := checkpointNameValid(name); err != nil {
68			return err
69		}
70		tag := prefix + name
71		out, err := gitpkg.Command(cmd.Context(), "", "tag", tag).CombinedOutput()
72		if err != nil {
73			msg := strings.TrimSpace(string(out))
74			if strings.Contains(msg, "not a git repository") {
75				return fmt.Errorf("not in a git repository; git features are unavailable")
76			}
77			if strings.Contains(msg, "already exists") {
78				return fmt.Errorf("checkpoint %q already exists", name)
79			}
80			return fmt.Errorf("git tag failed: %s", msg)
81		}
82		fmt.Fprintf(cmd.OutOrStdout(), "checkpoint created: %s\n", tag)
83		return nil
84	}
