86	func runCheckpointList(cmd *cobra.Command, prefix string) error {
87		pattern := prefix + "*"
88		out, err := gitpkg.Command(cmd.Context(), "", "tag", "-l", pattern).CombinedOutput()
89		if err != nil {
90			msg := strings.TrimSpace(string(out))
91			if strings.Contains(msg, "not a git repository") {
92				return fmt.Errorf("not in a git repository; git features are unavailable")
93			}
94			return fmt.Errorf("git tag failed: %s", msg)
95		}
96		output := strings.TrimRight(string(out), "\n")
97		if output == "" {
98			fmt.Fprintln(cmd.OutOrStdout(), "No checkpoints found.")
99			return nil
100		}
101		fmt.Fprintln(cmd.OutOrStdout(), output)
102		return nil
103	}
