105	func runCheckpointRestore(cmd *cobra.Command, prefix, name string) error {
106		if err := checkpointNameValid(name); err != nil {
107			return err
108		}
109		tag := prefix + name
110		out, err := gitpkg.Command(cmd.Context(), "", "checkout", tag).CombinedOutput()
111		if err != nil {
112			msg := strings.TrimSpace(string(out))
113			if strings.Contains(msg, "not a git repository") {
114				return fmt.Errorf("not in a git repository; git features are unavailable")
115			}
116			if strings.Contains(msg, "did not match") || strings.Contains(msg, "pathspec") {
117				return fmt.Errorf("checkpoint %q not found", name)
118			}
119			return fmt.Errorf("git checkout failed: %s", msg)
120		}
121		fmt.Fprintf(cmd.OutOrStdout(), "restored to checkpoint: %s\n", tag)
122		return nil
123	}
