package cmd

import (
	"context"
	"encoding/json"
	"fmt"
	"io"
	"os"
	"path/filepath"
	"strings"
	"time"

	gitpkg "github.com/DocumentDrivenDX/ddx/internal/git"
	"github.com/spf13/cobra"
)

// ddxManagedPaths are the only paths (relative to git root) that ddx sync is
// allowed to stash, stage, and commit. Nothing outside this list is ever touched.
var ddxManagedPaths = []string{
	".ddx/beads.jsonl",
	".ddx/executions",
	".ddx/plugins",
}

// SyncFailure is persisted to .ddx/sync-failure.json when sync aborts so that
// 'ddx doctor' can surface it without the user having to remember to check.
type SyncFailure struct {
	Timestamp time.Time `json:"timestamp"`
	Reason    string    `json:"reason"`
}

// syncGitRunner is the function type used to invoke git commands in sync operations.
// Extracted for testability — production code uses realSyncGitRun; tests inject fakes.
type syncGitRunner func(ctx context.Context, dir string, args ...string) ([]byte, error)

// realSyncGitRun runs a real git command via the standard gitpkg.Command wrapper.
func realSyncGitRun(ctx context.Context, dir string, args ...string) ([]byte, error) {
	return gitpkg.Command(ctx, dir, args...).CombinedOutput()
}

// checkSyncFailure reads the sync-failure.json at failurePath and returns a
// DiagnosticIssue if a recorded failure is found. Returns nil when the path
// does not exist or is unreadable.
func checkSyncFailure(failurePath string) *DiagnosticIssue {
	data, err := os.ReadFile(failurePath)
	if err != nil {
		return nil
	}
	var failure SyncFailure
	if err := json.Unmarshal(data, &failure); err != nil {
		return nil
	}
	return &DiagnosticIssue{
		Type: "sync_aborted",
		Description: fmt.Sprintf("sync aborted at %s: %s",
			failure.Timestamp.Format(time.RFC3339), failure.Reason),
		Remediation: []string{
			"Resolve the issue manually, then run 'ddx sync'",
			fmt.Sprintf("To clear this warning without syncing: rm %s", failurePath),
		},
	}
}

func (f *CommandFactory) newSyncCommand() *cobra.Command {
	var watchMode bool
	var interval time.Duration

	cmd := &cobra.Command{
		Use:   "sync",
		Short: "Synchronize DDx-managed files with origin",
		Long: `Synchronize DDx-managed files with origin/main.

The canonical sync flow:
  1. git fetch origin
  2. stash DDx-managed dirty files (.ddx/beads.jsonl, executions/, plugins/)
  3. git merge origin/main  (no rebase — preserves execute-bead history)
  4. git stash pop
  5. commit DDx-managed files with structured messages:
       .ddx/beads.jsonl  → "chore: tracker"
       .ddx/executions/  → "chore: add execution evidence"
  6. git push origin main  (retries once on non-fast-forward)

Sync never touches files outside the DDx-managed allowlist. Non-DDx dirty
files survive unchanged.

On abort (stash-pop conflict, double push failure), a failure record is
written to .ddx/sync-failure.json. Run 'ddx doctor' to surface it.`,
		RunE: func(cmd *cobra.Command, args []string) error {
			runner := f.syncGitRunnerOverride
			if runner == nil {
				runner = realSyncGitRun
			}
			return f.runSync(cmd, runner, watchMode, interval)
		},
	}
	cmd.Flags().BoolVar(&watchMode, "watch", false, "Run sync on an interval until killed")
	cmd.Flags().DurationVar(&interval, "interval", 15*time.Minute, "Interval between syncs (requires --watch)")
	return cmd
}

func (f *CommandFactory) runSync(cmd *cobra.Command, runner syncGitRunner, watch bool, interval time.Duration) error {
	repoRoot := gitpkg.FindProjectRoot(f.WorkingDir)
	ddxWorkspace := gitpkg.FindNearestDDxWorkspace(f.WorkingDir)
	if ddxWorkspace == "" {
		return fmt.Errorf("sync: no .ddx workspace found; run 'ddx init' first")
	}

	s := &syncer{
		repoRoot: repoRoot,
		ddxDir:   filepath.Join(ddxWorkspace, ".ddx"),
		runner:   runner,
		out:      cmd.OutOrStdout(),
	}

	if !watch {
		return s.run(cmd.Context())
	}

	fmt.Fprintf(s.out, "sync: watching (interval %s, Ctrl-C to stop)\n", interval)
	if err := s.run(cmd.Context()); err != nil {
		fmt.Fprintf(cmd.ErrOrStderr(), "sync: %v\n", err)
	}
	ticker := time.NewTicker(interval)
	defer ticker.Stop()
	for {
		select {
		case <-cmd.Context().Done():
			return nil
		case <-ticker.C:
			if err := s.run(cmd.Context()); err != nil {
				fmt.Fprintf(cmd.ErrOrStderr(), "sync: %v\n", err)
			}
		}
	}
}

// syncer holds the state for a single sync session.
type syncer struct {
	repoRoot string
	ddxDir   string
	runner   syncGitRunner
	out      io.Writer
}

func (s *syncer) git(ctx context.Context, args ...string) ([]byte, error) {
	return s.runner(ctx, s.repoRoot, args...)
}

func (s *syncer) writeFailure(reason string) error {
	failure := SyncFailure{Timestamp: time.Now().UTC(), Reason: reason}
	data, _ := json.Marshal(failure)
	_ = os.MkdirAll(s.ddxDir, 0o755)
	_ = os.WriteFile(filepath.Join(s.ddxDir, "sync-failure.json"), data, 0o644)
	return fmt.Errorf("sync aborted: %s", reason)
}

func (s *syncer) run(ctx context.Context) error {
	return s.runOnce(ctx, false)
}

func (s *syncer) runOnce(ctx context.Context, isRetry bool) error {
	// a. git fetch origin
	fmt.Fprintln(s.out, "sync: fetching origin...")
	if _, err := s.git(ctx, "fetch", "origin"); err != nil {
		return s.writeFailure(fmt.Sprintf("fetch failed: %v", err))
	}

	// b. stash DDx-managed dirty tracked files
	stashed, err := s.stashDDxPaths(ctx)
	if err != nil {
		return s.writeFailure(fmt.Sprintf("stash failed: %v", err))
	}

	// c. git merge origin/main (no rebase — preserves execute-bead history)
	fmt.Fprintln(s.out, "sync: merging origin/main...")
	if out, err := s.git(ctx, "merge", "origin/main"); err != nil {
		if stashed {
			_, _ = s.git(ctx, "stash", "pop")
		}
		return s.writeFailure(fmt.Sprintf("merge failed: %s", strings.TrimSpace(string(out))))
	}

	// d. git stash pop
	if stashed {
		fmt.Fprintln(s.out, "sync: applying stashed changes...")
		if out, err := s.git(ctx, "stash", "pop"); err != nil {
			return s.writeFailure(fmt.Sprintf("stash-pop conflict: resolve manually then run 'git stash pop' (%s)",
				strings.TrimSpace(string(out))))
		}
	}

	// e. commit DDx-managed dirty paths with structured messages
	if err := s.commitDDxPaths(ctx); err != nil {
		return s.writeFailure(fmt.Sprintf("commit failed: %v", err))
	}

	// f. git push origin main; retry once on non-fast-forward
	fmt.Fprintln(s.out, "sync: pushing to origin...")
	pushOut, pushErr := s.git(ctx, "push", "origin", "main")
	if pushErr != nil {
		pushMsg := string(pushOut)
		if isRetry {
			return s.writeFailure(fmt.Sprintf("push failed twice: %s", strings.TrimSpace(pushMsg)))
		}
		if strings.Contains(pushMsg, "non-fast-forward") || strings.Contains(pushMsg, "rejected") {
			fmt.Fprintln(s.out, "sync: push rejected (non-fast-forward), retrying from fetch...")
			return s.runOnce(ctx, true)
		}
		return s.writeFailure(fmt.Sprintf("push failed: %s", strings.TrimSpace(pushMsg)))
	}

	// Clear any existing failure marker on success.
	_ = os.Remove(filepath.Join(s.ddxDir, "sync-failure.json"))
	fmt.Fprintln(s.out, "sync: done")
	return nil
}

// stashDDxPaths stashes tracked dirty files in the DDx-managed allowlist.
// Returns true if a stash was created, false if there was nothing to stash.
// Untracked files (new execution artifacts) are not stashed; git merge
// does not affect them.
func (s *syncer) stashDDxPaths(ctx context.Context) (bool, error) {
	// Check for tracked dirty DDx paths (ignore untracked lines starting with "??").
	checkArgs := append([]string{"status", "--porcelain", "--"}, ddxManagedPaths...)
	out, err := s.git(ctx, checkArgs...)
	if err != nil {
		return false, fmt.Errorf("status check failed: %v", err)
	}
	hasTrackedDirty := false
	for _, line := range strings.Split(string(out), "\n") {
		if line == "" || strings.HasPrefix(line, "??") {
			continue
		}
		hasTrackedDirty = true
		break
	}
	if !hasTrackedDirty {
		return false, nil
	}

	stashArgs := append([]string{"stash", "push", "--"}, ddxManagedPaths...)
	if _, err := s.git(ctx, stashArgs...); err != nil {
		return false, fmt.Errorf("stash push failed: %v", err)
	}
	return true, nil
}

// commitDDxPaths stages and commits DDx-managed paths with structured messages.
// Commits only what is dirty; no-ops if a path group is clean.
func (s *syncer) commitDDxPaths(ctx context.Context) error {
	if err := s.commitIfDirty(ctx, []string{".ddx/beads.jsonl"}, "chore: tracker"); err != nil {
		return err
	}
	if err := s.commitIfDirty(ctx, []string{".ddx/executions", ".ddx/plugins"}, "chore: add execution evidence"); err != nil {
		return err
	}
	return nil
}

// commitIfDirty stages the given paths and commits them with message if they
// have any changes (staged, modified, or untracked). A no-op when clean.
func (s *syncer) commitIfDirty(ctx context.Context, paths []string, message string) error {
	checkArgs := append([]string{"status", "--porcelain", "--"}, paths...)
	out, err := s.git(ctx, checkArgs...)
	if err != nil {
		return fmt.Errorf("status check failed: %v", err)
	}
	if strings.TrimSpace(string(out)) == "" {
		return nil
	}

	addArgs := append([]string{"add", "--"}, paths...)
	if _, err := s.git(ctx, addArgs...); err != nil {
		return fmt.Errorf("git add failed: %v", err)
	}

	if _, err := s.git(ctx, "commit", "-m", message); err != nil {
		return fmt.Errorf("commit failed: %v", err)
	}
	return nil
}

package cmd

import (
	"bytes"
	"context"
	"encoding/json"
	"fmt"
	"os"
	"path/filepath"
	"strings"
	"testing"
	"time"
)

// fakeSyncGit records every git invocation and returns queued responses in order.
// Tests build the response queue to match the exact sequence of git calls for a
// given scenario.
type fakeSyncGit struct {
	responses []fakeGitResp
	idx       int
	allCalls  [][]string
}

type fakeGitResp struct {
	out []byte
	err error
}

func (f *fakeSyncGit) run(ctx context.Context, dir string, args ...string) ([]byte, error) {
	f.allCalls = append(f.allCalls, append([]string{}, args...))
	if f.idx >= len(f.responses) {
		return nil, nil
	}
	r := f.responses[f.idx]
	f.idx++
	return r.out, r.err
}

func ok() fakeGitResp                   { return fakeGitResp{} }
func outErr(out, e string) fakeGitResp  { return fakeGitResp{out: []byte(out), err: fmt.Errorf("%s", e)} }
func outOK(out string) fakeGitResp      { return fakeGitResp{out: []byte(out)} }

// cleanSyncSequence returns the ordered git responses for a sync run where:
//   - DDx paths are clean (no stash needed)
//   - merge succeeds
//   - all commit checks return empty (nothing to commit)
//   - push succeeds
func cleanSyncSequence() []fakeGitResp {
	return []fakeGitResp{
		ok(),         // fetch origin
		outOK(""),    // status --porcelain -- .ddx paths (clean)
		ok(),         // merge origin/main
		outOK(""),    // status --porcelain -- .ddx/beads.jsonl (clean)
		outOK(""),    // status --porcelain -- .ddx/executions .ddx/plugins (clean)
		ok(),         // push origin main
	}
}

// dirtySyncSequence returns ordered git responses for a sync run where
// .ddx/beads.jsonl is tracked-dirty and gets stashed/committed.
func dirtySyncSequence() []fakeGitResp {
	return []fakeGitResp{
		ok(),                             // fetch origin
		outOK(" M .ddx/beads.jsonl\n"),   // status --porcelain (tracked dirty)
		ok(),                             // stash push
		ok(),                             // merge origin/main
		ok(),                             // stash pop
		outOK(" M .ddx/beads.jsonl\n"),   // status before commit beads.jsonl
		ok(),                             // git add .ddx/beads.jsonl
		ok(),                             // git commit "chore: tracker"
		outOK(""),                        // status before commit executions/plugins
		ok(),                             // push origin main
	}
}

// makeTempDDxDir creates a temp dir with a .ddx subdirectory and returns both paths.
func makeTempDDxDir(t *testing.T) (repoRoot, ddxDir string) {
	t.Helper()
	repoRoot = t.TempDir()
	ddxDir = filepath.Join(repoRoot, ".ddx")
	if err := os.MkdirAll(ddxDir, 0o755); err != nil {
		t.Fatalf("mkdir .ddx: %v", err)
	}
	return repoRoot, ddxDir
}

func newSyncerFor(t *testing.T, fake *fakeSyncGit) (s *syncer, ddxDir string) {
	t.Helper()
	_, ddxDir = makeTempDDxDir(t)
	s = &syncer{
		repoRoot: filepath.Dir(ddxDir),
		ddxDir:   ddxDir,
		runner:   fake.run,
		out:      &bytes.Buffer{},
	}
	return s, ddxDir
}

// ---- AC3: Allowlist enforcement ----

// TestSync_UnrelatedDirtyFilesUntouched verifies that a file outside the
// DDx-managed allowlist is never passed to 'git add' during a sync run.
// A non-DDx dirty file (e.g. src/main.go) must survive the sync unchanged.
func TestSync_UnrelatedDirtyFilesUntouched(t *testing.T) {
	fake := &fakeSyncGit{responses: cleanSyncSequence()}
	s, _ := newSyncerFor(t, fake)

	if err := s.run(context.Background()); err != nil {
		t.Fatalf("unexpected error: %v", err)
	}

	for _, call := range fake.allCalls {
		if len(call) == 0 || call[0] != "add" {
			continue
		}
		for _, arg := range call[1:] {
			if arg == "--" {
				continue
			}
			allowed := false
			for _, p := range ddxManagedPaths {
				if strings.HasPrefix(arg, p) || arg == p {
					allowed = true
					break
				}
			}
			if !allowed {
				t.Errorf("git add called with non-DDx path %q; unrelated files must not be staged", arg)
			}
		}
	}
}

// ---- AC4: No destructive flags ----

// TestSync_NoForceOrNoVerifyFlags verifies that no git invocation during a
// sync run ever includes --force, --no-verify, or other destructive flags.
func TestSync_NoForceOrNoVerifyFlags(t *testing.T) {
	fake := &fakeSyncGit{responses: dirtySyncSequence()}
	s, _ := newSyncerFor(t, fake)
	_ = s.run(context.Background()) // outcome doesn't matter

	forbidden := []string{"--force", "-f", "--no-verify", "--force-with-lease", "--hard", "--delete"}
	for _, call := range fake.allCalls {
		for _, arg := range call {
			for _, bad := range forbidden {
				if arg == bad {
					t.Errorf("git call contained forbidden flag %q: %v", bad, call)
				}
			}
		}
	}
}

// ---- AC5: Stash-pop conflict aborts with structured exit ----

// TestSync_StashPopConflictAborts verifies that when 'git stash pop' fails
// (e.g. merge conflict), sync returns a non-nil error and writes
// sync-failure.json to .ddx/.
func TestSync_StashPopConflictAborts(t *testing.T) {
	responses := []fakeGitResp{
		ok(),                             // fetch origin
		outOK(" M .ddx/beads.jsonl\n"),   // status --porcelain (tracked dirty)
		ok(),                             // stash push
		ok(),                             // merge origin/main
		outErr("CONFLICT", "exit status 1"), // stash pop → conflict
	}
	fake := &fakeSyncGit{responses: responses}
	s, ddxDir := newSyncerFor(t, fake)

	err := s.run(context.Background())
	if err == nil {
		t.Fatal("expected error on stash-pop conflict, got nil")
	}
	if !strings.Contains(err.Error(), "stash-pop conflict") {
		t.Errorf("error message should mention 'stash-pop conflict', got: %v", err)
	}

	assertSyncFailureWritten(t, ddxDir, "stash-pop conflict")
}

// ---- AC5: Double push failure aborts with structured exit ----

// TestSync_DoublePushFailAborts verifies that when push fails twice (first
// rejected non-fast-forward, then rejected again on retry), sync returns a
// non-nil error and writes sync-failure.json.
func TestSync_DoublePushFailAborts(t *testing.T) {
	// First attempt: all clean, push rejected (non-fast-forward).
	// Second attempt (retry): all clean again, push rejected again.
	responses := []fakeGitResp{
		// First attempt
		ok(),      // fetch origin
		outOK(""), // status --porcelain -- .ddx paths (clean)
		ok(),      // merge origin/main
		outOK(""), // status beads.jsonl
		outOK(""), // status executions/plugins
		outErr("error: failed to push some refs\nhint: Updates were rejected because the remote contains work that you\nhint: do not have locally. Integrate the remote changes (e.g.\nhint: 'git pull ...') before pushing again.\nhint: See the 'Note about fast-forwards' in 'git push --help' for details.\nnon-fast-forward", "exit status 1"),
		// Retry (second attempt)
		ok(),      // fetch origin
		outOK(""), // status --porcelain -- .ddx paths
		ok(),      // merge origin/main
		outOK(""), // status beads.jsonl
		outOK(""), // status executions/plugins
		outErr("non-fast-forward", "exit status 1"), // push fails again
	}
	fake := &fakeSyncGit{responses: responses}
	s, ddxDir := newSyncerFor(t, fake)

	err := s.run(context.Background())
	if err == nil {
		t.Fatal("expected error on double push failure, got nil")
	}
	if !strings.Contains(err.Error(), "push failed twice") {
		t.Errorf("error message should mention 'push failed twice', got: %v", err)
	}

	assertSyncFailureWritten(t, ddxDir, "push failed twice")
}

// ---- AC6: Doctor surfaces sync failure ----

// TestDoctor_SyncFailureSurfaced verifies that checkSyncFailure returns a
// DiagnosticIssue describing the recorded failure when sync-failure.json exists.
func TestDoctor_SyncFailureSurfaced(t *testing.T) {
	dir := t.TempDir()
	failurePath := filepath.Join(dir, "sync-failure.json")

	ts := time.Date(2026, 4, 29, 12, 0, 0, 0, time.UTC)
	failure := SyncFailure{Timestamp: ts, Reason: "stash-pop conflict: merge conflict in .ddx/beads.jsonl"}
	data, _ := json.Marshal(failure)
	if err := os.WriteFile(failurePath, data, 0o644); err != nil {
		t.Fatalf("write failure file: %v", err)
	}

	issue := checkSyncFailure(failurePath)
	if issue == nil {
		t.Fatal("expected DiagnosticIssue, got nil")
	}
	if issue.Type != "sync_aborted" {
		t.Errorf("expected type sync_aborted, got %q", issue.Type)
	}
	if !strings.Contains(issue.Description, "stash-pop conflict") {
		t.Errorf("description should contain the stored reason, got: %q", issue.Description)
	}
	if !strings.Contains(issue.Description, "2026-04-29") {
		t.Errorf("description should contain the timestamp, got: %q", issue.Description)
	}
	if len(issue.Remediation) == 0 {
		t.Error("expected at least one remediation step")
	}
}

// TestDoctor_NoSyncFailureFile verifies that checkSyncFailure returns nil when
// there is no sync-failure.json (clean state).
func TestDoctor_NoSyncFailureFile(t *testing.T) {
	dir := t.TempDir()
	issue := checkSyncFailure(filepath.Join(dir, "sync-failure.json"))
	if issue != nil {
		t.Errorf("expected nil for missing failure file, got %+v", issue)
	}
}

// ---- Allowlist coverage: only DDx paths committed ----

// TestSync_CommitsOnlyDDxPaths verifies that when DDx files are dirty, only
// DDx-managed paths are staged — the git add args never include any other path.
func TestSync_CommitsOnlyDDxPaths(t *testing.T) {
	fake := &fakeSyncGit{responses: dirtySyncSequence()}
	s, _ := newSyncerFor(t, fake)

	if err := s.run(context.Background()); err != nil {
		t.Fatalf("unexpected error: %v", err)
	}

	for _, call := range fake.allCalls {
		if len(call) == 0 || call[0] != "add" {
			continue
		}
		// First arg after "add" should be "--"
		foundSep := false
		for i, arg := range call[1:] {
			if arg == "--" {
				foundSep = true
				continue
			}
			if !foundSep {
				continue
			}
			// Every path after "--" must be in the DDx allowlist.
			allowed := false
			for _, p := range ddxManagedPaths {
				if arg == p || strings.HasPrefix(arg, p+"/") {
					allowed = true
					break
				}
			}
			if !allowed {
				t.Errorf("git add[%d] staged non-DDx path %q", i, arg)
			}
		}
	}
}

// ---- Watch mode: exits cleanly on context cancel ----

// TestSync_WatchExitsOnContextCancel verifies that --watch mode exits promptly
// when its context is cancelled (simulating SIGINT / Ctrl-C).
func TestSync_WatchExitsOnContextCancel(t *testing.T) {
	// Provide enough clean responses for one sync cycle.
	fake := &fakeSyncGit{responses: cleanSyncSequence()}
	repoRoot, ddxDir := makeTempDDxDir(t)
	_ = ddxDir

	factory := &CommandFactory{WorkingDir: repoRoot, syncGitRunnerOverride: fake.run}
	rootCmd := factory.NewRootCommand()
	rootCmd.SetArgs([]string{"sync", "--watch", "--interval=100ms"})

	var buf bytes.Buffer
	rootCmd.SetOut(&buf)
	rootCmd.SetErr(&buf)

	ctx, cancel := context.WithTimeout(context.Background(), 500*time.Millisecond)
	defer cancel()

	// Run in a goroutine; it should return once ctx expires.
	done := make(chan error, 1)
	go func() {
		done <- rootCmd.ExecuteContext(ctx)
	}()

	select {
	case <-done:
		// Exited as expected (either clean or context error).
	case <-time.After(2 * time.Second):
		t.Fatal("--watch mode did not exit within 2s after context cancel")
	}
}

// ---- Helpers ----

func assertSyncFailureWritten(t *testing.T, ddxDir, reasonSubstr string) {
	t.Helper()
	failurePath := filepath.Join(ddxDir, "sync-failure.json")
	data, err := os.ReadFile(failurePath)
	if err != nil {
		t.Fatalf("sync-failure.json not written: %v", err)
	}
	var failure SyncFailure
	if err := json.Unmarshal(data, &failure); err != nil {
		t.Fatalf("sync-failure.json not valid JSON: %v", err)
	}
	if failure.Reason == "" {
		t.Error("sync-failure.json has empty reason")
	}
	if !strings.Contains(failure.Reason, reasonSubstr) {
		t.Errorf("sync-failure.json reason should contain %q, got %q", reasonSubstr, failure.Reason)
	}
	if failure.Timestamp.IsZero() {
		t.Error("sync-failure.json has zero timestamp")
	}
}

